{"path": "/tmp/pass-or-yass/src/index.ts", "content": "import { Hono } from "hono";
import { SPEC_VERSION, type SnapFunction } from "@farcaster/snap";
import { registerSnapHandler } from "@farcaster/snap-hono";
import {
  createInMemoryDataStore,
  createTursoDataStore,
} from "@farcaster/snap-turso";

// ─── Config ───────────────────────────────────────────────────────
const NEYNAR_BASE = "https://api.neynar.com/v2/farcaster";
const NEYNAR_KEY = process.env.NEYNAR_API_KEY ?? "";
const DAILY_SWIPE_LIMIT = 50;
const MIN_ACCOUNT_AGE_DAYS = 180;
const MIN_NEYNAR_SCORE = 0.42;
const MIN_POSTS_6M = 10;
const MIN_ORIGINAL_6M = 3;
const MAX_DELETED_CASTS = 20;
const MAX_POOL_SIZE = 80;
const SPEC = SPEC_VERSION;

// ─── Data Store ───────────────────────────────────────────────────
const store =
  process.env.VERCEL === "1"
    ? createTursoDataStore()
    : createInMemoryDataStore();

// ─── Types ────────────────────────────────────────────────────────
interface NeynarUser {
  fid: number;
  username: string;
  display_name: string;
  pfp_url: string;
  profile: { bio: { text: string } };
  follower_count: number;
  following_count: number;
  power_badge: boolean;
  score: number;
  verifications: string[];
  registered_at: string;
}

interface NeynarCast {
  hash: string;
  text: string;
  parent_hash: string | null;
  parent_url: string | null;
  timestamp: string;
  embeds: unknown[];
  frames: unknown[];
  attachments?: unknown[];
  type?: string;
}

interface QualResult {
  qualified: boolean;
  accountAgeDays: number;
  neynarScore: number;
  followerRatio: number;
  postCount: number;
  originalContent: number;
  deletedCasts: number;
}

interface Profile {
  fid: number;
  username: string;
  displayName: string;
  pfpUrl: string;
  bio: string;
  followers: number;
  following: number;
}

// ─── Neynar API ───────────────────────────────────────────────────
async function neynarFetch<T>(path: string): Promise<T | null> {
  if (!NEYNAR_KEY) return null;
  try {
    const res = await fetch(`${NEYNAR_BASE}${path}`, {
      headers: { api_key: NEYNAR_KEY },
    });
    if (!res.ok) {
      console.error(`Neynar ${path}: ${res.status} ${res.statusText}`);
      return null;
    }
    return (await res.json()) as T;
  } catch (e) {
    console.error(`Neynar fetch error ${path}:`, e);
    return null;
  }
}

async function fetchUser(fid: number): Promise<NeynarUser | null> {
  const data = await neynarFetch<{ users: NeynarUser[] }>(
    `/user/bulk?fids=${fid}`
  );
  return data?.users?.[0] ?? null;
}

async function fetchUserCasts(
  fid: number,
  limit = 25
): Promise<NeynarCast[]> {
  const data = await neynarFetch<{ casts: NeynarCast[] }>(
    `/feed?feed_type=filter&filter_type=fids&fids=${fid}&limit=${limit}`
  );
  return data?.casts ?? [];
}

async function fetchFollowing(fid: number): Promise<number[]> {
  const data = await neynarFetch<{ users: NeynarUser[] }>(
    `/following?fid=${fid}&limit=100`
  );
  return data?.users?.map((u) => u.fid) ?? [];
}

async function fetchTrendingUsers(limit = 50): Promise<NeynarUser[]> {
  const data = await neynarFetch<{ users: NeynarUser[] }>(
    `/user/trending?limit=${limit}`
  );
  return data?.users ?? [];
}

async function fetchActiveUsers(limit = 50): Promise<NeynarUser[]> {
  // Fetch from the trending feed to find active users
  const data = await neynarFetch<{ casts: NeynarCast[] }>(
    `/feed?feed_type=filter&filter_type=global_trending&limit=${limit}`
  );
  const fids = [
    ...new Set(data?.casts?.map((c: any) => c.author?.fid).filter(Boolean) ?? []),
  ];
  if (fids.length === 0) return [];
  const userData = await neynarFetch<{ users: NeynarUser[] }>(
    `/user/bulk?fids=${fids.slice(0, 50).join(",")}`
  );
  return userData?.users ?? [];
}

// ─── Qualification Logic ──────────────────────────────────────────
function quickQualify(user: NeynarUser): boolean {
  const accountAgeDays = daysSince(user.registered_at);
  const ratio = user.following_count > 0
    ? user.follower_count / user.following_count
    : user.follower_count > 0 ? 999 : 0;
  return (
    accountAgeDays >= MIN_ACCOUNT_AGE_DAYS &&
    (user.score ?? 0) >= MIN_NEYNAR_SCORE &&
    ratio >= 0.15 &&
    user.follower_count >= 10
  );
}

async function fullQualify(fid: number): Promise<QualResult> {
  const user = await fetchUser(fid);
  if (!user) {
    return {
      qualified: false,
      accountAgeDays: 0,
      neynarScore: 0,
      followerRatio: 0,
      postCount: 0,
      originalContent: 0,
      deletedCasts: 0,
    };
  }

  const accountAgeDays = daysSince(user.registered_at);
  const neynarScore = user.score ?? 0;
  const followerRatio =
    user.following_count > 0
      ? user.follower_count / user.following_count
      : user.follower_count > 0 ? 999 : 0;

  // Fetch casts from last 6 months
  const sixMonthsAgo = Date.now() - 180 * 24 * 60 * 60 * 1000;
  const allCasts = await fetchUserCasts(fid, 50);
  const recentCasts = allCasts.filter(
    (c) => new Date(c.timestamp).getTime() > sixMonthsAgo
  );

  // Count original content (has embeds/attachments with media)
  const originalContent = recentCasts.filter((c) => {
    const hasEmbeds = (c.embeds?.length ?? 0) > 0;
    const hasAttachments = (c.attachments?.length ?? 0) > 0;
    const hasFrames = (c.frames?.length ?? 0) > 0;
    const isOriginal = !c.parent_hash && !c.parent_url;
    return isOriginal && (hasEmbeds || hasAttachments || hasFrames);
  }).length;

  // Estimate deleted casts: total from user metadata minus what we fetched
  const totalCasts = (user as any).caster_score ?? allCasts.length;
  const deletedCasts = Math.max(0, totalCasts - allCasts.length);

  const qualified =
    accountAgeDays >= MIN_ACCOUNT_AGE_DAYS &&
    neynarScore >= MIN_NEYNAR_SCORE &&
    followerRatio >= 0.15 &&
    recentCasts.length >= MIN_POSTS_6M &&
    originalContent >= MIN_ORIGINAL_6M &&
    deletedCasts < MAX_DELETED_CASTS;

  return {
    qualified,
    accountAgeDays,
    neynarScore,
    followerRatio,
    postCount: recentCasts.length,
    originalContent,
    deletedCasts,
  };
}

// ─── Helpers ──────────────────────────────────────────────────────
function daysSince(dateStr: string): number {
  return Math.floor(
    (Date.now() - new Date(dateStr).getTime()) / (1000 * 60 * 60 * 24)
  );
}

function todayKey(): string {
  return new Date().toISOString().slice(0, 10); // YYYY-MM-DD
}

function clamp(s: string, max: number): string {
  return s.length <= max ? s : s.slice(0, max - 3) + "...";
}

function baseUrl(request: Request): string {
  const fromEnv = process.env.SNAP_PUBLIC_BASE_URL?.trim();
  if (fromEnv) return fromEnv.replace(/\/$/, "");
  const host = request.headers.get("x-forwarded-host")?.split(",")[0].trim()
    ?? request.headers.get("host")?.split(",")[0].trim();
  const isLoopback = host && /^(localhost|127\.0\.0\.1|\[::1\]|::1)(:\d+)?$/.test(host);
  const proto = request.headers.get("x-forwarded-proto")?.split(",")[0].trim().toLowerCase()
    ?? (isLoopback ? "http" : "https");
  if (host) return `${proto}://${host}`.replace(/\/$/, "");
  return `http://localhost:${process.env.PORT ?? "3003"}`.replace(/\/$/, "");
}

// ─── Turso Helpers ────────────────────────────────────────────────
async function getBehavioralTag(fid: number): Promise<string | null> {
  const data = (await store.get(`bt:${fid}`)) as any;
  return data?.tag ?? null;
}

async function setBehavioralTag(fid: number, tag: string): Promise<void> {
  await store.set(`bt:${fid}`, { tag, timestamp: Date.now() });
}

async function getQualification(fid: number): Promise<any | null> {
  return ((await store.get(`qual:${fid}`)) as any) ?? null;
}

async function setQualification(fid: number, result: any): Promise<void> {
  await store.set(`qual:${fid}`, { ...result, checkedAt: Date.now() });
}

async function getSwipeCount(fid: number): Promise<number> {
  const data = (await store.get(`sc:${fid}:${todayKey()}`)) as any;
  return data?.count ?? 0;
}

async function incrementSwipe(fid: number): Promise<number> {
  const key = `sc:${fid}:${todayKey()}`;
  const data = (await store.get(key)) as any;
  const count = (data?.count ?? 0) + 1;
  await store.set(key, { count });
  return count;
}

async function recordSwipe(
  swiperFid: number,
  targetFid: number,
  direction: string,
  tag: string
): Promise<void> {
  const key = `swipes:${swiperFid}`;
  const data = (await store.get(key)) as any;
  const swipes: any[] = data?.swipes ?? [];
  swipes.push({ targetFid, direction, tag, ts: Date.now() });
  await store.set(key, { swipes });
}

async function getSwipedFids(fid: number): Promise<Set<number>> {
  const data = (await store.get(`swipes:${fid}`)) as any;
  return new Set((data?.swipes ?? []).map((s: any) => s.targetFid));
}

async function getProfilePool(fid: number): Promise<Profile[]> {
  const data = (await store.get(`pool:${fid}`)) as any;
  return data?.profiles ?? [];
}

async function setProfilePool(fid: number, profiles: Profile[]): Promise<void> {
  await store.set(`pool:${fid}`, { profiles, builtAt: Date.now() });
}

// ─── Profile Pool Builder ─────────────────────────────────────────
async function buildProfilePool(
  swiperFid: number,
  connections: Set<number>
): Promise<Profile[]> {
  // Gather candidate users from multiple sources
  const [trending, active] = await Promise.all([
    fetchTrendingUsers(50),
    fetchActiveUsers(50),
  ]);

  const allUsers = [...trending, ...active];
  const seen = new Set<number>();
  const candidates: NeynarUser[] = [];

  for (const u of allUsers) {
    if (seen.has(u.fid)) continue;
    seen.add(u.fid);
    // Exclude swiper and their connections
    if (u.fid === swiperFid || connections.has(u.fid)) continue;
    // Quick filter: basic sanity
    if (!quickQualify(u)) continue;
    candidates.push(u);
  }

  // Shuffle candidates
  for (let i = candidates.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [candidates[i], candidates[j]] = [candidates[j], candidates[i]];
  }

  // Full qualify in batches (limit to avoid timeout)
  const qualified: Profile[] = [];
  const alreadySwiped = await getSwipedFids(swiperFid);
  const checkBatch = candidates.slice(0, 30);

  for (const candidate of checkBatch) {
    if (qualified.length >= MAX_POOL_SIZE) break;
    if (alreadySwiped.has(candidate.fid)) continue;

    const qual = await fullQualify(candidate.fid);
    if (qual.qualified) {
      qualified.push({
        fid: candidate.fid,
        username: candidate.username,
        displayName: candidate.display_name,
        pfpUrl: candidate.pfp_url,
        bio: clamp(candidate.profile?.bio?.text ?? "", 160),
        followers: candidate.follower_count,
        following: candidate.following_count,
      });
    }
  }

  return qualified;
}

